PROGRAM Hello;
BEGIN
  WRITELN('Hello, World!');
END.

PROGRAM Counting;
VAR I: Integer;
BEGIN
  FOR I := 1 TO 10 DO
    WRITELN(I);
END.

PROGRAM Loop;
VAR X: Integer;
BEGIN
  X := 0;
  WHILE X < 5 DO BEGIN
    WRITELN(X);
    X := X + 1;
  END;
END.

PROGRAM Procs;
PROCEDURE Greet(Name: String);
BEGIN
  WRITELN('Hello, ', Name);
END;
BEGIN
  Greet('World');
END.

PROGRAM Funcs;
FUNCTION Square(N: Integer): Integer;
BEGIN
  Square := N * N;
END;
BEGIN
  WRITELN(Square(7));
END.

PROGRAM Recs;
TYPE TPoint = RECORD
  X: Integer;
  Y: Integer;
END;
VAR P: TPoint;
BEGIN
  P.X := 10;
  P.Y := 20;
  WRITELN(P.X, ' ', P.Y);
END.

